SELECT COUNT(*) FROM (
    SELECT r.report_no FROM REPORT r
    JOIN ITEM i ON r.target_no = i.item_no
    WHERE r.target_type = 'item' AND i.user_no = #{userNo}
    UNION ALL
    SELECT r.report_no FROM REPORT r
    JOIN BOARD_POST b ON r.target_no = b.board_no
    WHERE r.target_type = 'board' AND b.user_no = #{userNo}
    UNION ALL
    SELECT r.report_no FROM REPORT r
    JOIN REPLY rp ON r.target_no = rp.reply_no
    WHERE r.target_type = 'reply' AND rp.user_no = #{userNo}
)

SELECT * FROM (
    SELECT b.*, ROW_NUMBER() OVER (PARTITION BY b.item_no ORDER BY b.bid_price DESC) rn
    FROM BID b WHERE b.user_no = #{userNo}
) t WHERE rn = 1

SELECT * FROM BOARD_POST WHERE user_no = #{userNo}

    AND board_cd_no = #{category}

ORDER BY board_date DESC

mapper.update:
UPDATE MEMBER SET user_name = #{userName}, user_address = #{userAddress},
                  user_phone = #{userPhone}, user_email = #{userEmail}
WHERE user_no = #{userNo}
